terraform {
  backend "s3" {
    bucket         = "acme-tf-state"
    key            = "prod/network/terraform.tfstate"
    region         = "eu-west-1"
    encrypt        = true             # encrypt state at rest (it holds secrets!)
    dynamodb_table = "tf-locks"       # state LOCKING via DynamoDB
  }
}

variable "environment" {
  type    = string
  default = "staging"
}

provider "aws" {
  region = "eu-west-1"
}

# A reusable module called twice with different inputs.
module "network" {
  source      = "./modules/vpc"
  cidr_block  = "10.0.0.0/16"
  environment = var.environment
}

resource "aws_instance" "web" {
  ami           = data.aws_ami.ubuntu.id   # data source: reads, does not manage
  instance_type = "t3.micro"
  subnet_id     = module.network.public_subnet_id   # consume a module output
  tags = { Name = "web-${var.environment}" }
}

output "web_ip" {
  value = aws_instance.web.public_ip
}

# count: indexed by position -> FRAGILE if the list changes order/middle removed.
variable "users" { default = ["alice", "bob", "carol"] }
resource "aws_iam_user" "by_count" {
  count = length(var.users)
  name  = var.users[count.index]      # user[0]=alice, user[1]=bob, user[2]=carol
}
# Remove "bob": carol shifts from index 2 to 1 -> Terraform destroys & recreates carol!

# for_each: keyed by a stable identifier -> SAFE under add/remove.
resource "aws_iam_user" "by_each" {
  for_each = toset(var.users)
  name     = each.value                # user["alice"], user["bob"], user["carol"]
}
# Remove "bob": only user["bob"] is destroyed; alice and carol are untouched.

resource "aws_vpc" "main" { cidr_block = "10.0.0.0/16" }

resource "aws_subnet" "app" {
  vpc_id     = aws_vpc.main.id          # implicit dependency: vpc before subnet
  cidr_block = "10.0.1.0/24"
}

resource "aws_instance" "app" {
  subnet_id  = aws_subnet.app.id
  ami        = data.aws_ami.ubuntu.id
  depends_on = [aws_iam_role_policy.app]  # explicit: no attribute ref, but must exist first
}

variable "db_password" {
  type      = string
  sensitive = true            # redacts from plan/apply output and logs ONLY
}

# Better: fetch secrets at apply time from a secret manager instead of passing them in.
data "aws_secretsmanager_secret_version" "db" {
  secret_id = "prod/db/password"
}

resource "aws_db_instance" "main" {
  username = "app"
  password = data.aws_secretsmanager_secret_version.db.secret_string   # still lands in state
  # ... but the source of truth is the secret manager, rotatable independently.
}

