terraform {
  required_version = ">= 1.5.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"        # pin provider for reproducible plans
    }
  }

  backend "s3" {
    bucket         = "acme-tf-state"
    key            = "prod/network/terraform.tfstate"  # per-env, per-stack isolation
    region         = "eu-west-1"
    encrypt        = true                               # SSE for state at rest
    dynamodb_table = "tf-state-locks"                   # enables state LOCKING
  }
}

